// IdentityServiceServer is the server API for IdentityService service.
// All implementations must embed UnimplementedIdentityServiceServer
// for forward compatibility.
//
// IdentityService provides operations for user management, authentication,
// onboarding, and external credential management.
type IdentityServiceServer interface {
	// FindUser retrieves a user by username. It can be used for authentication and user lookup.
	FindUser(context.Context, *FindUserRequest) (*v1.User, error)
	// GetUsers retrieves a list of users with pagination support.
	GetUsers(context.Context, *GetUsersRequest) (*UserList, error)
	// IssueUserToken issues a new JWT access token for a user
	IssueUserToken(context.Context, *IssueUserTokenRequest) (*IssueUserTokenResponse, error)
	// GetUserOnboardCapability checks if the identity provider supports onboarding and returns the capability details.
	GetUserOnboardCapability(context.Context, *Username) (*v1.UserOnboardCapability, error)
	// OnboardUserDeviceFlow initiates the device flow onboarding process for a user.
	OnboardUserDeviceFlow(context.Context, *OnboardUserDeviceFlowRequest) (*v1.OnboardUserDeviceFlow, error)
	// OnboardUserWebFlow initiates the web flow onboarding process for a user.
	OnboardUserWebFlow(context.Context, *OnboardUserWebFlowRequest) (*v1.OnboardUserWebFlow, error)
	// CompleteUserWebFlow completes the web flow onboarding process using the provided state and code.
	CompleteUserWebFlow(context.Context, *CompleteUserWebFlowRequest) (*CompleteUserWebFlowResponse, error)
	// AuthUserPublicKey authenticates a user using a public key and returns the authentication result
	// along with user details if valid.
	AuthUserPublicKey(context.Context, *AuthUserPublicKeyRequest) (*AuthUserResponse, error)
	// AuthUserPassword checks a password against a user's stored bcrypt hash and
	// returns the result along with user details if valid. It does not evaluate
	// the user:auth authz policy itself — it is shared by SSH and web login
	// surfaces (and by non-login callers, e.g. requiring the current password
	// before a change), each of which is responsible for its own authorization.
	AuthUserPassword(context.Context, *AuthUserPasswordRequest) (*AuthUserResponse, error)
	// CompleteUserDeviceFlow is called by the client after the user has completed
	// device-flow authorization on the provider side. It provisions the git
	// credential and returns the user's access token.
	CompleteUserDeviceFlow(context.Context, *CompleteUserDeviceFlowRequest) (*CompleteUserDeviceFlowResponse, error)
	// GetBlueprintByUserStr retrieves a blueprint associated with a user string identifier.
	GetBlueprintByUserStr(context.Context, *UserStr) (*Blueprint, error)
	// ListUserCredentials retrieves all credentials associated with a user, or a single
	// credential when id is set.
	ListUserCredentials(context.Context, *ListUserCredentialsRequest) (*ListUserCredentialsResponse, error)
	// GetUserCredential retrieves a specific credential for a user by service name and scope.
	GetUserCredential(context.Context, *GetUserCredentialRequest) (*v1.UserCredential, error)
	// AddKubernetesUserCredential provisions a Kubernetes service-account credential for a user.
	// The secret is left unset — kubernetes credentials are resolved on demand via the
	// TokenRequest API when the credential is fetched.
	AddKubernetesUserCredential(context.Context, *AddKubernetesUserCredentialRequest) (*AddKubernetesUserCredentialResponse, error)
	// AddGitUserCredential stores a Git credential for a user. credential_source is always
	// "stored" — the secret is persisted as given and returned as-is on resolution.
	AddGitUserCredential(context.Context, *AddGitUserCredentialRequest) (*AddGitUserCredentialResponse, error)
	// AddRegistryUserCredential stores a container registry credential for a user.
	// credential_source is always "stored" — the secret is persisted as given and returned
	// as-is on resolution.
	AddRegistryUserCredential(context.Context, *AddRegistryUserCredentialRequest) (*AddRegistryUserCredentialResponse, error)
	// CreateUser creates a new local user record. The supplied password, if any,
	// is bcrypt-hashed server-side before being persisted, the same as SetUserPassword.
	CreateUser(context.Context, *CreateUserRequest) (*v1.User, error)
	// UpdateUser applies a partial update to a user record. Only fields wrapped
	// in a value type (or repeated fields that are non-empty) are applied.
	UpdateUser(context.Context, *UpdateUserRequest) (*v1.User, error)
	// DeleteUser permanently removes a user record by username. Credentials and
	// access tokens owned by the user are removed along with it (ON DELETE CASCADE).
	DeleteUser(context.Context, *DeleteUserRequest) (*DeleteUserResponse, error)
	// AddUserRoles adds one or more roles to a user without affecting existing roles.
	AddUserRoles(context.Context, *UserRolesRequest) (*v1.User, error)
	// RemoveUserRoles removes one or more roles from a user.
	RemoveUserRoles(context.Context, *UserRolesRequest) (*v1.User, error)
	// AddUserBlueprints grants a user access to one or more blueprints.
	AddUserBlueprints(context.Context, *UserBlueprintsRequest) (*v1.User, error)
	// RemoveUserBlueprints revokes access to one or more blueprints from a user.
	RemoveUserBlueprints(context.Context, *UserBlueprintsRequest) (*v1.User, error)
	// ListUserAuthKeys retrieves all SSH public keys registered for a user, in
	// either normal or digest-only form depending on the request's format field.
	ListUserAuthKeys(context.Context, *ListUserAuthKeysRequest) (*ListUserAuthKeysResponse, error)
	// AddUserAuthKeys registers one or more SSH public keys for a user.
	AddUserAuthKeys(context.Context, *UserAuthKeysRequest) (*v1.User, error)
	// RemoveUserAuthKey removes a single SSH public key from a user, identified
	// by its index in the list returned by ListUserAuthKeys.
	RemoveUserAuthKey(context.Context, *RemoveUserAuthKeyRequest) (*v1.User, error)
	// SetUserPassword sets or replaces a user's local password, used by AuthUserPassword.
	// The supplied password is bcrypt-hashed server-side before being persisted; it is
	// never stored or returned in plaintext. Pass an empty password to clear it, which
	// disables password auth for the user.
	SetUserPassword(context.Context, *SetUserPasswordRequest) (*v1.User, error)
	// UpdateUserCredential partially updates a credential by ID. Only fields wrapped in a value
	// type that are set (non-nil) are applied. Credentials whose credential_source matches
	// "idp.k8shell.io/*" — provisioned by the onboarding flow — may only have active updated;
	// attempts to change scope, subject, or secret are rejected.
	UpdateUserCredential(context.Context, *UpdateUserCredentialRequest) (*UpdateUserCredentialResponse, error)
	// DeleteUserCredential deletes an external credential by its ID.
	DeleteUserCredential(context.Context, *DeleteUserCredentialRequest) (*DeleteUserCredentialResponse, error)
	// RemoveUserCredential removes a specific credential owned by a user, identified by ID.
	RemoveUserCredential(context.Context, *RemoveUserCredentialRequest) (*RemoveUserCredentialResponse, error)
	// GetAvailableIdentityProviders returns a list of available identity providers.
	GetAvailableIdentityProviders(context.Context, *GetAvailableIdentityProvidersRequest) (*GetAvailableIdentityProvidersResponse, error)
	// CreateAccessToken issues a new Personal Access Token for a user. The raw token is
	// returned once in the response and is not recoverable after that.
	CreateAccessToken(context.Context, *CreateAccessTokenRequest) (*CreateAccessTokenResponse, error)
	// ListAccessTokens returns access token metadata (no raw tokens or hashes) for a user.
	ListAccessTokens(context.Context, *Username) (*ListAccessTokensResponse, error)
	// RevokeAccessToken soft-deletes an access token by ID, enforcing username ownership.
	RevokeAccessToken(context.Context, *RevokeAccessTokenRequest) (*RevokeAccessTokenResponse, error)
	// ResolveAccessToken looks up an access token by its raw value, updates last_used_at,
	// and returns the owning user plus the token's scopes. Called by API gateways
	// on every request that carries a k8sh_ token.
	ResolveAccessToken(context.Context, *ResolveAccessTokenRequest) (*ResolveAccessTokenResponse, error)
	mustEmbedUnimplementedIdentityServiceServer()
}

